import{_ as a,o as s,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"83. Special Disaster Leave","description":"","frontmatter":{"title":"83. Special Disaster Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","personal-leave","employment"]},"headers":[],"relativePath":"ebas/mspp/leave/83-special-disaster-leave.md","filePath":"ebas/mspp/leave/83-special-disaster-leave.md"}'),o={name:"ebas/mspp/leave/83-special-disaster-leave.md"};function i(l,e,n,p,c,d){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_83-special-disaster-leave" tabindex="-1">83. Special Disaster Leave <a class="header-anchor" href="#_83-special-disaster-leave" aria-label="Permalink to &quot;83. Special Disaster Leave&quot;">​</a></h1><p><strong>a.</strong> Special disaster leave of up to 3 days per calendar year is payable where:</p><p><strong>(i)</strong> the Employee is a full time or part time employee;</p><p><strong>(ii)</strong> Personal/Carer’s Leave is not available either because the Employee has exhausted the accrual or the circumstance does not qualify for Personal Leave; and</p><p><strong>(iii)</strong> the Employee is unable to attend work due to a disaster (such as fire or flood) where: <strong>(A)</strong> the Employee&#39;s residence is damaged or under imminent threat of major damage; <strong>(B)</strong> the lives or safety of their immediate family or household members are threatened; or <strong>(C)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Employee&#39;s normal travel</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>route to work and no alternative practicable travel route is available.</p><p><strong>b.</strong> Special disaster leave is non-cumulative.</p><p>Plain language terms: disaster leave, flood, bushfire.</p>',9)])])}const u=a(o,[["render",i]]);export{h as __pageData,u as default};
